const fs   = require('fs');
const path = require('path');

const files = {
  "app/admin/dashboard/page.tsx": "import { createClient } from '@/lib/supabase/server'\nimport { formatDate } from '@/lib/utils'\nimport { TIER_LABELS } from '@/types'\nimport Link from 'next/link'\nimport { Users, BookOpen, ClipboardList, TrendingUp } from 'lucide-react'\n\nexport default async function AdminDashboardPage() {\n  const supabase = await createClient()\n  const [\n    { count: totalStudents },\n    { count: activeStudents },\n    { count: totalQuestions },\n    { count: totalAssignments },\n    { data: recentStudents },\n    { data: tierRaw },\n  ] = await Promise.all([\n    supabase.from('users').select('*', { count: 'exact', head: true }).eq('role', 'student'),\n    supabase.from('users').select('*', { count: 'exact', head: true }).eq('role', 'student').eq('status', 'active'),\n    supabase.from('questions').select('*', { count: 'exact', head: true }),\n    supabase.from('assignments').select('*', { count: 'exact', head: true }),\n    supabase.from('users').select('id, full_name, email, tier, status, created_at')\n      .eq('role', 'student').order('created_at', { ascending: false }).limit(6),\n    supabase.from('users').select('tier').eq('role', 'student').eq('status', 'active').not('tier', 'is', null),\n  ])\n\n  const tierCounts: Record<number, number> = { 1: 0, 2: 0, 3: 0, 4: 0 }\n  tierRaw?.forEach(u => { if (u.tier) tierCounts[u.tier] = (tierCounts[u.tier] || 0) + 1 })\n  const maxTier = Math.max(1, ...Object.values(tierCounts))\n\n  return (\n    <div className=\"p-6 max-w-6xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <h1 className=\"page-title\">Dashboard</h1>\n          <p className=\"page-subtitle\">T\u1ed5ng quan h\u1ec7 th\u1ed1ng SAT Platform</p>\n        </div>\n        <span className=\"text-xs text-gray-400\">\n          {new Date().toLocaleDateString('vi-VN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}\n        </span>\n      </div>\n\n      <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6\">\n        {[\n          { label: 'T\u1ed5ng h\u1ecdc vi\u00ean',  value: totalStudents    ?? 0, icon: Users,         bg: 'bg-blue-50',    color: 'text-blue-600'    },\n          { label: '\u0110ang ho\u1ea1t \u0111\u1ed9ng', value: activeStudents   ?? 0, icon: TrendingUp,    bg: 'bg-emerald-50', color: 'text-emerald-600' },\n          { label: 'C\u00e2u h\u1ecfi',        value: totalQuestions   ?? 0, icon: BookOpen,      bg: 'bg-purple-50',  color: 'text-purple-600'  },\n          { label: 'B\u00e0i t\u1eadp',        value: totalAssignments ?? 0, icon: ClipboardList, bg: 'bg-amber-50',   color: 'text-amber-600'   },\n        ].map(({ label, value, icon: Icon, bg, color }) => (\n          <div key={label} className=\"stat-card\">\n            <div className={`stat-icon ${bg}`}><Icon size={20} className={color} /></div>\n            <div>\n              <p className=\"text-xs text-gray-500 font-medium\">{label}</p>\n              <p className=\"text-2xl font-bold text-gray-900 mt-0.5\">{value}</p>\n            </div>\n          </div>\n        ))}\n      </div>\n\n      <div className=\"grid grid-cols-3 gap-5\">\n        <div className=\"card col-span-1\">\n          <div className=\"card-header\">\n            <h2 className=\"text-sm font-semibold text-gray-900\">Ph\u00e2n b\u1ed1 Tier</h2>\n          </div>\n          <div className=\"card-body space-y-4\">\n            {([1, 2, 3, 4] as const).map(tier => {\n              const count = tierCounts[tier]\n              const pct   = maxTier > 0 ? (count / maxTier) * 100 : 0\n              const fills = ['bg-blue-400', 'bg-emerald-400', 'bg-amber-400', 'bg-purple-400']\n              return (\n                <div key={tier}>\n                  <div className=\"flex justify-between items-center mb-1.5\">\n                    <span className=\"text-xs text-gray-600\">{TIER_LABELS[tier]}</span>\n                    <span className=\"text-xs font-bold text-gray-900 tabular-nums\">{count}</span>\n                  </div>\n                  <div className=\"progress-track\">\n                    <div className={`progress-fill ${fills[tier - 1]}`} style={{ width: `${pct}%` }} />\n                  </div>\n                </div>\n              )\n            })}\n            <p className=\"text-xs text-gray-400 pt-1\">\n              {Object.values(tierCounts).reduce((a, b) => a + b, 0)} h\u1ecdc vi\u00ean c\u00f3 Tier\n            </p>\n          </div>\n        </div>\n\n        <div className=\"card col-span-2\">\n          <div className=\"card-header\">\n            <h2 className=\"text-sm font-semibold text-gray-900\">H\u1ecdc vi\u00ean m\u1edbi nh\u1ea5t</h2>\n            <Link href=\"/admin/users\" className=\"text-xs text-blue-600 hover:underline font-medium\">Xem t\u1ea5t c\u1ea3 \u2192</Link>\n          </div>\n          <div className=\"table-wrap\">\n            <table className=\"table\">\n              <thead>\n                <tr><th>H\u1ecd t\u00ean</th><th>Email</th><th>Tier</th><th>Tr\u1ea1ng th\u00e1i</th><th>Ng\u00e0y tham gia</th></tr>\n              </thead>\n              <tbody>\n                {recentStudents?.map(s => (\n                  <tr key={s.id}>\n                    <td className=\"font-medium text-gray-900\">{s.full_name}</td>\n                    <td className=\"text-gray-500 text-xs\">{s.email}</td>\n                    <td>{s.tier ? <span className=\"badge badge-blue\">Tier {s.tier}</span> : <span className=\"text-gray-300 text-xs\">\u2014</span>}</td>\n                    <td>{s.status === 'active' ? <span className=\"badge badge-green\">Active</span> : <span className=\"badge badge-red\">Inactive</span>}</td>\n                    <td className=\"text-gray-400 text-xs\">{formatDate(s.created_at)}</td>\n                  </tr>\n                ))}\n                {!recentStudents?.length && (\n                  <tr><td colSpan={5}>\n                    <div className=\"empty-state py-10\">\n                      <Users size={32} className=\"text-gray-200 mb-2\" />\n                      <p className=\"text-sm text-gray-400\">Ch\u01b0a c\u00f3 h\u1ecdc vi\u00ean n\u00e0o</p>\n                    </div>\n                  </td></tr>\n                )}\n              </tbody>\n            </table>\n          </div>\n        </div>\n      </div>\n    </div>\n  )\n}\n",
  "app/admin/users/actions.ts": "'use server'\n\nimport { revalidatePath } from 'next/cache'\nimport { createAdminClient } from '@/lib/supabase/admin'\nimport { generateTempPassword } from '@/lib/utils'\nimport { sendWelcomeEmail } from '@/lib/email'\n\nexport async function createStudent(formData: FormData) {\n  const email     = formData.get('email')     as string\n  const fullName  = formData.get('full_name') as string\n  const courseId  = formData.get('course_id') as string\n  const expiresAt = formData.get('expires_at') as string\n\n  const admin = createAdminClient()\n  const tempPassword = generateTempPassword()\n\n  const { data: authUser, error: authError } = await admin.auth.admin.createUser({\n    email, password: tempPassword, email_confirm: true,\n  })\n  if (authError) return { error: authError.message }\n\n  const { error: profileError } = await admin.from('users').insert({\n    auth_id: authUser.user.id,\n    email, full_name: fullName,\n    role: 'student', status: 'active',\n  })\n  if (profileError) return { error: profileError.message }\n\n  if (courseId) {\n    const { data: profile } = await admin.from('users').select('id').eq('auth_id', authUser.user.id).single()\n    if (profile) {\n      await admin.from('enrollments').insert({\n        user_id: profile.id, course_id: courseId,\n        expires_at: expiresAt || null,\n      })\n    }\n  }\n\n  try { await sendWelcomeEmail(email, fullName, tempPassword) } catch {}\n  revalidatePath('/admin/users')\n  return { success: true }\n}\n\nexport async function toggleUserStatus(userId: string, currentStatus: string) {\n  const admin = createAdminClient()\n  const newStatus = currentStatus === 'active' ? 'inactive' : 'active'\n  const { data: profile } = await admin.from('users').select('auth_id').eq('id', userId).single()\n  const { error } = await admin.from('users').update({ status: newStatus }).eq('id', userId)\n  if (error) return { error: error.message }\n  if (newStatus === 'inactive' && profile?.auth_id) {\n    try { await admin.auth.admin.signOut(profile.auth_id, 'global') } catch {}\n  }\n  revalidatePath('/admin/users')\n  return { success: true }\n}\n\nexport async function updateUserTier(userId: string, tier: number) {\n  const admin = createAdminClient()\n  const { error } = await admin.from('users').update({ tier }).eq('id', userId)\n  if (error) return { error: error.message }\n  revalidatePath('/admin/users')\n  return { success: true }\n}\n\nexport async function importStudentsFromCSV(\n  rows: Array<{ email: string; full_name: string; course_id?: string; expires_at?: string }>\n) {\n  const results = []\n  for (const row of rows) {\n    const fd = new FormData()\n    fd.set('email', row.email)\n    fd.set('full_name', row.full_name)\n    if (row.course_id) fd.set('course_id', row.course_id)\n    if (row.expires_at) fd.set('expires_at', row.expires_at)\n    results.push({ ...row, ...await createStudent(fd) })\n  }\n  return results\n}\n",
  "app/admin/users/page.tsx": "'use client'\n\nimport { useState, useEffect, useTransition } from 'react'\nimport { createClient } from '@/lib/supabase/client'\nimport { formatDate, isExpired } from '@/lib/utils'\nimport { Search, UserPlus, Upload, Download } from 'lucide-react'\nimport CreateUserModal from './CreateUserModal'\nimport ImportCSVModal from './ImportCSVModal'\nimport UserActions from './UserActions'\n\nexport default function AdminUsersPage() {\n  const [students, setStudents]     = useState<any[]>([])\n  const [search, setSearch]         = useState('')\n  const [filterStatus, setFilter]   = useState('all')\n  const [loading, setLoading]       = useState(true)\n  const [showCreate, setShowCreate] = useState(false)\n  const [showImport, setShowImport] = useState(false)\n\n  async function load() {\n    setLoading(true)\n    const supabase = createClient()\n    let q = supabase\n      .from('users')\n      .select('id, full_name, email, tier, status, created_at, enrollments(expires_at, courses(name))')\n      .eq('role', 'student')\n      .order('created_at', { ascending: false })\n    if (filterStatus !== 'all') q = (q as any).eq('status', filterStatus)\n    if (search.trim()) q = (q as any).ilike('full_name', `%${search}%`)\n    const { data } = await q\n    setStudents(data ?? [])\n    setLoading(false)\n  }\n\n  useEffect(() => { load() }, [search, filterStatus])\n\n  const active   = students.filter(s => s.status === 'active').length\n  const inactive = students.filter(s => s.status === 'inactive').length\n\n  async function handleExport() {\n    const header = 'H\u1ecd t\u00ean,Email,Tier,Tr\u1ea1ng th\u00e1i,Kh\u00f3a h\u1ecdc,H\u1ebft h\u1ea1n,Ng\u00e0y tham gia\\n'\n    const rows   = students.map(s => [\n      s.full_name, s.email, s.tier ?? '', s.status,\n      s.enrollments?.[0]?.courses?.name ?? '',\n      s.enrollments?.[0]?.expires_at ?? '',\n      formatDate(s.created_at),\n    ].join(','))\n    const a = document.createElement('a')\n    a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(header + rows.join('\\n'))\n    a.download = `students_${new Date().toISOString().slice(0,10)}.csv`\n    a.click()\n  }\n\n  return (\n    <div className=\"p-6 max-w-7xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <h1 className=\"page-title\">Qu\u1ea3n l\u00fd h\u1ecdc vi\u00ean</h1>\n          <p className=\"page-subtitle\">Th\u00eam, xem v\u00e0 qu\u1ea3n l\u00fd t\u00e0i kho\u1ea3n h\u1ecdc vi\u00ean</p>\n        </div>\n        <div className=\"flex gap-2\">\n          <button onClick={handleExport} className=\"btn-secondary\"><Download size={15} /> Xu\u1ea5t CSV</button>\n          <button onClick={() => setShowImport(true)} className=\"btn-secondary\"><Upload size={15} /> Nh\u1eadp CSV</button>\n          <button onClick={() => setShowCreate(true)} className=\"btn-primary\"><UserPlus size={15} /> Th\u00eam h\u1ecdc vi\u00ean</button>\n        </div>\n      </div>\n\n      <div className=\"grid grid-cols-3 gap-4 mb-5\">\n        {[\n          { label: 'T\u1ed5ng',     value: students.length, color: 'text-gray-900'    },\n          { label: '\u0110ang h\u1ecdc', value: active,          color: 'text-emerald-600' },\n          { label: '\u0110\u00e3 t\u1eaft',   value: inactive,        color: 'text-red-500'     },\n        ].map(({ label, value, color }) => (\n          <div key={label} className=\"card px-5 py-4\">\n            <p className=\"text-xs text-gray-500 font-medium\">{label}</p>\n            <p className={`text-3xl font-bold mt-1 ${color}`}>{value}</p>\n          </div>\n        ))}\n      </div>\n\n      <div className=\"flex gap-3 mb-5\">\n        <div className=\"relative flex-1 max-w-sm\">\n          <Search size={15} className=\"absolute left-3 top-1/2 -translate-y-1/2 text-gray-400\" />\n          <input className=\"input pl-9\" placeholder=\"T\u00ecm theo t\u00ean h\u1ecdc vi\u00ean\u2026\"\n            value={search} onChange={e => setSearch(e.target.value)} />\n        </div>\n        <select className=\"input w-40\" value={filterStatus} onChange={e => setFilter(e.target.value)}>\n          <option value=\"all\">T\u1ea5t c\u1ea3</option>\n          <option value=\"active\">\u0110ang h\u1ecdc</option>\n          <option value=\"inactive\">\u0110\u00e3 t\u1eaft</option>\n        </select>\n      </div>\n\n      <div className=\"card\">\n        <div className=\"table-wrap\">\n          <table className=\"table\">\n            <thead>\n              <tr>\n                <th>H\u1ecdc vi\u00ean</th><th>Tier</th><th>Kh\u00f3a h\u1ecdc</th>\n                <th>H\u1ebft h\u1ea1n</th><th>Tr\u1ea1ng th\u00e1i</th><th>Ng\u00e0y tham gia</th><th></th>\n              </tr>\n            </thead>\n            <tbody>\n              {loading ? (\n                <tr><td colSpan={7} className=\"text-center py-12 text-gray-400\">\u0110ang t\u1ea3i\u2026</td></tr>\n              ) : students.length === 0 ? (\n                <tr><td colSpan={7} className=\"text-center py-12 text-gray-400\">Kh\u00f4ng t\u00ecm th\u1ea5y h\u1ecdc vi\u00ean</td></tr>\n              ) : students.map(s => {\n                const enroll  = s.enrollments?.[0]\n                const expired = isExpired(enroll?.expires_at)\n                return (\n                  <tr key={s.id}>\n                    <td>\n                      <div className=\"font-medium text-gray-900\">{s.full_name}</div>\n                      <div className=\"text-xs text-gray-400\">{s.email}</div>\n                    </td>\n                    <td>\n                      {s.tier\n                        ? <span className=\"badge badge-blue\">Tier {s.tier}</span>\n                        : <span className=\"text-gray-300 text-xs\">Ch\u01b0a ph\u00e2n</span>}\n                    </td>\n                    <td className=\"text-sm text-gray-600\">{enroll?.courses?.name ?? '\u2014'}</td>\n                    <td>\n                      {enroll?.expires_at\n                        ? <span className={expired ? 'text-red-500 text-xs font-medium' : 'text-gray-500 text-xs'}>\n                            {formatDate(enroll.expires_at)}{expired ? ' \u26a0' : ''}\n                          </span>\n                        : <span className=\"text-gray-300 text-xs\">\u2014</span>}\n                    </td>\n                    <td>\n                      {s.status === 'active'\n                        ? <span className=\"badge badge-green\">Active</span>\n                        : <span className=\"badge badge-red\">Inactive</span>}\n                    </td>\n                    <td className=\"text-xs text-gray-400\">{formatDate(s.created_at)}</td>\n                    <td><UserActions id={s.id} status={s.status} onDone={load} /></td>\n                  </tr>\n                )\n              })}\n            </tbody>\n          </table>\n        </div>\n      </div>\n\n      {showCreate && <CreateUserModal onClose={() => { setShowCreate(false); load() }} />}\n      {showImport && <ImportCSVModal onClose={() => { setShowImport(false); load() }} />}\n    </div>\n  )\n}\n",
  "app/admin/users/CreateUserModal.tsx": "'use client'\n\nimport { useState, useTransition } from 'react'\nimport { createStudent } from './actions'\nimport { X } from 'lucide-react'\n\nexport default function CreateUserModal({ onClose }: { onClose: () => void }) {\n  const [form, setForm]     = useState({ email: '', full_name: '', expires_at: '' })\n  const [error, setError]   = useState('')\n  const [success, setSuccess] = useState('')\n  const [isPending, start]  = useTransition()\n\n  function set(k: string, v: string) { setForm(f => ({ ...f, [k]: v })) }\n\n  function handleSubmit(e: React.FormEvent) {\n    e.preventDefault()\n    setError(''); setSuccess('')\n    const fd = new FormData()\n    Object.entries(form).forEach(([k, v]) => { if (v) fd.set(k, v) })\n    start(async () => {\n      const res = await createStudent(fd)\n      if (res.error) { setError(res.error); return }\n      setSuccess('T\u1ea1o t\u00e0i kho\u1ea3n th\u00e0nh c\u00f4ng! Email \u0111\u00e3 \u0111\u01b0\u1ee3c g\u1eedi.')\n      setTimeout(onClose, 1500)\n    })\n  }\n\n  return (\n    <div className=\"modal-backdrop\">\n      <div className=\"modal w-full max-w-md\">\n        <div className=\"flex items-center justify-between mb-5\">\n          <h2 className=\"text-base font-semibold text-gray-900\">Th\u00eam h\u1ecdc vi\u00ean m\u1edbi</h2>\n          <button onClick={onClose} className=\"p-1 text-gray-400 hover:text-gray-600\"><X size={18} /></button>\n        </div>\n        {error   && <div className=\"alert-error mb-4\">{error}</div>}\n        {success && <div className=\"alert-success mb-4\">{success}</div>}\n        <form onSubmit={handleSubmit} className=\"space-y-4\">\n          <div>\n            <label className=\"label\">H\u1ecd v\u00e0 t\u00ean *</label>\n            <input className=\"input\" placeholder=\"Nguy\u1ec5n V\u0103n A\"\n              value={form.full_name} onChange={e => set('full_name', e.target.value)} required />\n          </div>\n          <div>\n            <label className=\"label\">Email *</label>\n            <input className=\"input\" type=\"email\" placeholder=\"student@example.com\"\n              value={form.email} onChange={e => set('email', e.target.value)} required />\n          </div>\n          <div>\n            <label className=\"label\">Ng\u00e0y h\u1ebft h\u1ea1n</label>\n            <input className=\"input\" type=\"date\"\n              value={form.expires_at} onChange={e => set('expires_at', e.target.value)} />\n            <p className=\"text-xs text-gray-400 mt-1\">\u0110\u1ec3 tr\u1ed1ng n\u1ebfu kh\u00f4ng gi\u1edbi h\u1ea1n th\u1eddi gian</p>\n          </div>\n          <div className=\"flex gap-3 pt-2\">\n            <button type=\"button\" onClick={onClose} className=\"btn-secondary flex-1\">Hu\u1ef7</button>\n            <button type=\"submit\" disabled={isPending} className=\"btn-primary flex-1 justify-center\">\n              {isPending ? '\u0110ang t\u1ea1o\u2026' : 'T\u1ea1o t\u00e0i kho\u1ea3n'}\n            </button>\n          </div>\n        </form>\n        <p className=\"text-xs text-gray-400 mt-4\">M\u1eadt kh\u1ea9u t\u1ea1m s\u1ebd \u0111\u01b0\u1ee3c g\u1eedi t\u1ef1 \u0111\u1ed9ng qua email.</p>\n      </div>\n    </div>\n  )\n}\n",
  "app/admin/users/ImportCSVModal.tsx": "'use client'\n\nimport { useState, useTransition } from 'react'\nimport { importStudentsFromCSV } from './actions'\nimport { X, Upload, CheckCircle, AlertCircle } from 'lucide-react'\nimport Papa from 'papaparse'\n\nexport default function ImportCSVModal({ onClose }: { onClose: () => void }) {\n  const [rows, setRows]       = useState<any[]>([])\n  const [parseError, setPErr] = useState('')\n  const [results, setResults] = useState<any[]>([])\n  const [isPending, start]    = useTransition()\n\n  function handleFile(e: React.ChangeEvent<HTMLInputElement>) {\n    const file = e.target.files?.[0]\n    if (!file) return\n    Papa.parse(file, {\n      header: true, skipEmptyLines: true,\n      complete: ({ data, errors }) => {\n        if (errors.length) { setPErr(errors[0].message); return }\n        setPErr('')\n        setRows((data as any[]).filter(r => r.email && r.full_name))\n      }\n    })\n  }\n\n  function handleImport() {\n    start(async () => {\n      const res = await importStudentsFromCSV(rows)\n      setResults(res)\n    })\n  }\n\n  const done   = results.filter(r => r.success).length\n  const failed = results.filter(r => r.error).length\n\n  return (\n    <div className=\"modal-backdrop\">\n      <div className=\"modal w-full max-w-xl\">\n        <div className=\"flex items-center justify-between mb-5\">\n          <h2 className=\"text-base font-semibold text-gray-900\">Nh\u1eadp h\u1ecdc vi\u00ean t\u1eeb CSV</h2>\n          <button onClick={onClose} className=\"p-1 text-gray-400 hover:text-gray-600\"><X size={18} /></button>\n        </div>\n\n        {results.length === 0 ? (\n          <>\n            <div className=\"border-2 border-dashed border-gray-200 rounded-xl p-8 text-center mb-4\">\n              <Upload size={28} className=\"text-gray-300 mx-auto mb-3\" />\n              <p className=\"text-sm text-gray-600 mb-1 font-medium\">Ch\u1ecdn file CSV</p>\n              <p className=\"text-xs text-gray-400 mb-4\">C\u1ed9t b\u1eaft bu\u1ed9c: email, full_name. Tu\u1ef3 ch\u1ecdn: expires_at</p>\n              <label className=\"btn-secondary cursor-pointer inline-flex\">\n                <input type=\"file\" accept=\".csv\" className=\"hidden\" onChange={handleFile} />\n                Ch\u1ecdn file\n              </label>\n            </div>\n            {parseError && <div className=\"alert-error mb-4\">{parseError}</div>}\n            {rows.length > 0 && (\n              <>\n                <p className=\"text-sm font-medium text-gray-600 mb-3\">{rows.length} h\u1ecdc vi\u00ean s\u1ebd \u0111\u01b0\u1ee3c nh\u1eadp</p>\n                <div className=\"max-h-40 overflow-y-auto table-wrap mb-4\">\n                  <table className=\"table text-xs\">\n                    <thead><tr><th>H\u1ecd t\u00ean</th><th>Email</th><th>H\u1ebft h\u1ea1n</th></tr></thead>\n                    <tbody>\n                      {rows.slice(0, 8).map((r, i) => (\n                        <tr key={i}><td>{r.full_name}</td><td>{r.email}</td><td>{r.expires_at || '\u2014'}</td></tr>\n                      ))}\n                    </tbody>\n                  </table>\n                </div>\n                <div className=\"flex gap-3\">\n                  <button onClick={onClose} className=\"btn-secondary flex-1\">Hu\u1ef7</button>\n                  <button onClick={handleImport} disabled={isPending} className=\"btn-primary flex-1 justify-center\">\n                    {isPending ? '\u0110ang nh\u1eadp\u2026' : `Nh\u1eadp ${rows.length} h\u1ecdc vi\u00ean`}\n                  </button>\n                </div>\n              </>\n            )}\n          </>\n        ) : (\n          <div className=\"space-y-2\">\n            <div className=\"flex gap-3 mb-4\">\n              {done   > 0 && <span className=\"badge badge-green\"><CheckCircle size={13}/> {done} th\u00e0nh c\u00f4ng</span>}\n              {failed > 0 && <span className=\"badge badge-red\"><AlertCircle size={13}/> {failed} th\u1ea5t b\u1ea1i</span>}\n            </div>\n            <div className=\"max-h-60 overflow-y-auto space-y-1\">\n              {results.map((r, i) => (\n                <div key={i} className={`flex items-center gap-2 text-sm px-3 py-2 rounded-lg ${r.success ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-700'}`}>\n                  {r.success ? <CheckCircle size={14}/> : <AlertCircle size={14}/>}\n                  <span className=\"font-medium\">{r.full_name}</span>\n                  <span className=\"text-xs opacity-60\">{r.email}</span>\n                  {r.error && <span className=\"ml-auto text-xs\">{r.error}</span>}\n                </div>\n              ))}\n            </div>\n            <button onClick={onClose} className=\"btn-primary w-full justify-center mt-4\">\u0110\u00f3ng</button>\n          </div>\n        )}\n      </div>\n    </div>\n  )\n}\n",
  "app/admin/users/UserActions.tsx": "'use client'\n\nimport { useTransition } from 'react'\nimport { toggleUserStatus } from './actions'\nimport { Power, PowerOff } from 'lucide-react'\n\ninterface Props { id: string; status: string; onDone: () => void }\n\nexport default function UserActions({ id, status, onDone }: Props) {\n  const [isPending, start] = useTransition()\n  const isActive = status === 'active'\n\n  function handleToggle() {\n    if (!confirm(isActive ? 'T\u1eaft t\u00e0i kho\u1ea3n h\u1ecdc vi\u00ean n\u00e0y?' : 'K\u00edch ho\u1ea1t l\u1ea1i t\u00e0i kho\u1ea3n?')) return\n    start(async () => { await toggleUserStatus(id, status); onDone() })\n  }\n\n  return (\n    <button onClick={handleToggle} disabled={isPending} title={isActive ? 'T\u1eaft' : 'B\u1eadt'}\n      className={`inline-flex items-center gap-1.5 text-xs font-medium px-2.5 py-1.5 rounded-lg transition-colors\n        ${isActive ? 'text-red-600 hover:bg-red-50' : 'text-emerald-600 hover:bg-emerald-50'}\n        ${isPending ? 'opacity-50 cursor-not-allowed' : ''}`}>\n      {isActive ? <PowerOff size={14}/> : <Power size={14}/>}\n      {isActive ? 'T\u1eaft' : 'B\u1eadt'}\n    </button>\n  )\n}\n",
  "app/admin/questions/actions.ts": "'use server'\n\nimport { revalidatePath } from 'next/cache'\nimport { createAdminClient } from '@/lib/supabase/admin'\n\nexport async function createQuestion(formData: FormData) {\n  const admin = createAdminClient()\n  const payload = {\n    domain:         formData.get('domain')         as string,\n    skill:          formData.get('skill')          as string,\n    difficulty:     formData.get('difficulty')     as string,\n    source:         formData.get('source')         as string || null,\n    content:        formData.get('content')        as string,\n    option_a:       formData.get('option_a')       as string,\n    option_b:       formData.get('option_b')       as string,\n    option_c:       formData.get('option_c')       as string,\n    option_d:       formData.get('option_d')       as string,\n    correct_answer: formData.get('correct_answer') as string,\n    explanation:    formData.get('explanation')    as string || null,\n  }\n  const { error } = await admin.from('questions').insert(payload)\n  if (error) return { error: error.message }\n  revalidatePath('/admin/questions')\n  return { success: true }\n}\n\nexport async function deleteQuestion(id: string) {\n  const admin = createAdminClient()\n  const { error } = await admin.from('questions').delete().eq('id', id)\n  if (error) return { error: error.message }\n  revalidatePath('/admin/questions')\n  return { success: true }\n}\n\nexport async function importQuestionsFromCSV(rows: Array<Record<string, string>>) {\n  const admin    = createAdminClient()\n  const required = ['domain','skill','difficulty','content','option_a','option_b','option_c','option_d','correct_answer']\n  const valid    = rows.filter(r => required.every(k => r[k]))\n  if (!valid.length) return { error: 'Kh\u00f4ng c\u00f3 d\u00f2ng h\u1ee3p l\u1ec7', count: 0 }\n  const { error } = await admin.from('questions').insert(valid)\n  if (error) return { error: error.message, count: 0 }\n  revalidatePath('/admin/questions')\n  return { success: true, count: valid.length }\n}\n",
  "app/admin/questions/page.tsx": "'use client'\n\nimport { useState, useEffect } from 'react'\nimport { createClient } from '@/lib/supabase/client'\nimport { formatDate } from '@/lib/utils'\nimport { MATH_SKILLS, RW_SKILLS } from '@/types'\nimport Link from 'next/link'\nimport { Plus, Upload, Search, BookOpen } from 'lucide-react'\nimport QuestionImportModal from './QuestionImportModal'\nimport QuestionDeleteBtn from './QuestionDeleteBtn'\n\nconst PAGE_SIZE = 20\n\nexport default function AdminQuestionsPage() {\n  const [questions, setQuestions]     = useState<any[]>([])\n  const [total, setTotal]             = useState(0)\n  const [page, setPage]               = useState(0)\n  const [loading, setLoading]         = useState(true)\n  const [showImport, setShowImport]   = useState(false)\n  const [domain, setDomain]           = useState('')\n  const [skill, setSkill]             = useState('')\n  const [difficulty, setDifficulty]   = useState('')\n  const [search, setSearch]           = useState('')\n\n  const domainSkills = domain === 'Math' ? [...MATH_SKILLS] : domain === 'Reading & Writing' ? [...RW_SKILLS] : []\n\n  async function load() {\n    setLoading(true)\n    const supabase = createClient()\n    let q = supabase.from('questions')\n      .select('id, domain, skill, difficulty, source, content, correct_answer, created_at', { count: 'exact' })\n      .order('created_at', { ascending: false })\n      .range(page * PAGE_SIZE, (page + 1) * PAGE_SIZE - 1)\n    if (domain)     q = (q as any).eq('domain', domain)\n    if (skill)      q = (q as any).eq('skill', skill)\n    if (difficulty) q = (q as any).eq('difficulty', difficulty)\n    if (search.trim()) q = (q as any).ilike('content', `%${search}%`)\n    const { data, count } = await q\n    setQuestions(data ?? [])\n    setTotal(count ?? 0)\n    setLoading(false)\n  }\n\n  useEffect(() => { load() }, [page, domain, skill, difficulty, search])\n\n  const totalPages = Math.ceil(total / PAGE_SIZE)\n  const diffColor: Record<string, string> = {\n    Easy: 'badge-green', Medium: 'badge-yellow', Hard: 'badge-red',\n  }\n\n  return (\n    <div className=\"p-6 max-w-7xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <h1 className=\"page-title\">Ng\u00e2n h\u00e0ng c\u00e2u h\u1ecfi</h1>\n          <p className=\"page-subtitle\">{total.toLocaleString()} c\u00e2u h\u1ecfi</p>\n        </div>\n        <div className=\"flex gap-2\">\n          <button onClick={() => setShowImport(true)} className=\"btn-secondary\"><Upload size={15}/> Nh\u1eadp CSV</button>\n          <Link href=\"/admin/questions/new\" className=\"btn-primary\"><Plus size={15}/> Th\u00eam c\u00e2u h\u1ecfi</Link>\n        </div>\n      </div>\n\n      <div className=\"flex flex-wrap gap-3 mb-5\">\n        <div className=\"relative\">\n          <Search size={14} className=\"absolute left-3 top-1/2 -translate-y-1/2 text-gray-400\"/>\n          <input className=\"input pl-9 w-56\" placeholder=\"T\u00ecm trong n\u1ed9i dung\u2026\"\n            value={search} onChange={e => { setSearch(e.target.value); setPage(0) }}/>\n        </div>\n        <select className=\"input w-44\" value={domain} onChange={e => { setDomain(e.target.value); setSkill(''); setPage(0) }}>\n          <option value=\"\">T\u1ea5t c\u1ea3 domain</option>\n          <option value=\"Math\">Math</option>\n          <option value=\"Reading & Writing\">Reading &amp; Writing</option>\n        </select>\n        {domainSkills.length > 0 && (\n          <select className=\"input w-56\" value={skill} onChange={e => { setSkill(e.target.value); setPage(0) }}>\n            <option value=\"\">T\u1ea5t c\u1ea3 skill</option>\n            {domainSkills.map(s => <option key={s} value={s}>{s}</option>)}\n          </select>\n        )}\n        <select className=\"input w-36\" value={difficulty} onChange={e => { setDifficulty(e.target.value); setPage(0) }}>\n          <option value=\"\">T\u1ea5t c\u1ea3 \u0111\u1ed9 kh\u00f3</option>\n          <option value=\"Easy\">Easy</option>\n          <option value=\"Medium\">Medium</option>\n          <option value=\"Hard\">Hard</option>\n        </select>\n        {(domain || skill || difficulty || search) && (\n          <button className=\"btn-secondary text-xs\"\n            onClick={() => { setDomain(''); setSkill(''); setDifficulty(''); setSearch(''); setPage(0) }}>\n            Xo\u00e1 filter\n          </button>\n        )}\n      </div>\n\n      <div className=\"card\">\n        <div className=\"table-wrap\">\n          <table className=\"table\">\n            <thead>\n              <tr>\n                <th className=\"w-10\">#</th><th>N\u1ed9i dung</th><th>Domain</th>\n                <th>Skill</th><th>\u0110\u1ed9 kh\u00f3</th><th>\u0110\u00e1p \u00e1n</th><th>Ng\u00e0y t\u1ea1o</th><th></th>\n              </tr>\n            </thead>\n            <tbody>\n              {loading ? (\n                <tr><td colSpan={8} className=\"text-center py-12 text-gray-400\">\u0110ang t\u1ea3i\u2026</td></tr>\n              ) : questions.length === 0 ? (\n                <tr><td colSpan={8}>\n                  <div className=\"empty-state py-16\">\n                    <BookOpen size={40} className=\"text-gray-200 mb-3\"/>\n                    <p className=\"text-gray-400\">Ch\u01b0a c\u00f3 c\u00e2u h\u1ecfi n\u00e0o</p>\n                    <Link href=\"/admin/questions/new\" className=\"btn-primary mt-4 text-sm\">\n                      <Plus size={14}/> Th\u00eam c\u00e2u h\u1ecfi \u0111\u1ea7u ti\u00ean\n                    </Link>\n                  </div>\n                </td></tr>\n              ) : questions.map((q, idx) => (\n                <tr key={q.id}>\n                  <td className=\"text-gray-400 text-xs tabular-nums\">{page * PAGE_SIZE + idx + 1}</td>\n                  <td className=\"max-w-xs\">\n                    <p className=\"text-sm text-gray-800 truncate\">{q.content.slice(0, 80)}{q.content.length > 80 ? '\u2026' : ''}</p>\n                    {q.source && <p className=\"text-xs text-gray-400 mt-0.5\">{q.source}</p>}\n                  </td>\n                  <td><span className=\"badge badge-blue text-xs\">{q.domain === 'Math' ? 'Math' : 'R&W'}</span></td>\n                  <td className=\"text-xs text-gray-600 max-w-[140px] truncate\">{q.skill}</td>\n                  <td><span className={`badge ${diffColor[q.difficulty] ?? ''}`}>{q.difficulty}</span></td>\n                  <td><span className=\"font-bold text-blue-600\">{q.correct_answer}</span></td>\n                  <td className=\"text-xs text-gray-400\">{formatDate(q.created_at)}</td>\n                  <td><QuestionDeleteBtn id={q.id} onDone={load}/></td>\n                </tr>\n              ))}\n            </tbody>\n          </table>\n        </div>\n        {totalPages > 1 && (\n          <div className=\"px-5 py-3 border-t border-gray-100 flex items-center justify-between\">\n            <span className=\"text-xs text-gray-500\">Trang {page+1}/{totalPages} \u2014 {total} c\u00e2u h\u1ecfi</span>\n            <div className=\"flex gap-1.5\">\n              <button disabled={page === 0} onClick={() => setPage(p => p-1)} className=\"btn-secondary text-xs px-3 py-1.5\">\u2190 Tr\u01b0\u1edbc</button>\n              <button disabled={page >= totalPages-1} onClick={() => setPage(p => p+1)} className=\"btn-secondary text-xs px-3 py-1.5\">Ti\u1ebfp \u2192</button>\n            </div>\n          </div>\n        )}\n      </div>\n      {showImport && <QuestionImportModal onClose={() => { setShowImport(false); load() }}/>}\n    </div>\n  )\n}\n",
  "app/admin/questions/new/page.tsx": "'use client'\n\nimport { useState, useTransition } from 'react'\nimport { useRouter } from 'next/navigation'\nimport { createQuestion } from '../actions'\nimport { MATH_SKILLS, RW_SKILLS } from '@/types'\nimport { KaTeXPreview } from '@/components/math/KaTeX'\nimport { ArrowLeft, Eye } from 'lucide-react'\nimport Link from 'next/link'\n\nconst DOMAINS     = ['Math', 'Reading & Writing'] as const\nconst DIFFICULTIES = ['Easy', 'Medium', 'Hard']    as const\nconst ANSWERS     = ['A', 'B', 'C', 'D']           as const\n\nexport default function NewQuestionPage() {\n  const router = useRouter()\n  const [isPending, start] = useTransition()\n  const [error, setError]  = useState('')\n  const [preview, setPreview] = useState(false)\n  const [form, setForm] = useState({\n    domain: 'Math', skill: '', difficulty: 'Medium', source: '',\n    content: '', option_a: '', option_b: '', option_c: '', option_d: '',\n    correct_answer: 'A', explanation: '',\n  })\n\n  const skills = form.domain === 'Math' ? [...MATH_SKILLS] : [...RW_SKILLS]\n  function set(k: string, v: string) {\n    setForm(f => ({ ...f, [k]: v, ...(k === 'domain' ? { skill: '' } : {}) }))\n  }\n\n  function handleSubmit(e: React.FormEvent) {\n    e.preventDefault()\n    if (!form.skill) { setError('Vui l\u00f2ng ch\u1ecdn Skill'); return }\n    setError('')\n    const fd = new FormData()\n    Object.entries(form).forEach(([k, v]) => fd.set(k, v))\n    start(async () => {\n      const res = await createQuestion(fd)\n      if (res.error) { setError(res.error); return }\n      router.push('/admin/questions')\n    })\n  }\n\n  return (\n    <div className=\"p-6 max-w-6xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <Link href=\"/admin/questions\" className=\"flex items-center gap-1.5 text-sm text-gray-500 hover:text-gray-800 mb-1\">\n            <ArrowLeft size={14}/> Quay l\u1ea1i\n          </Link>\n          <h1 className=\"page-title\">Th\u00eam c\u00e2u h\u1ecfi m\u1edbi</h1>\n        </div>\n        <button type=\"button\" onClick={() => setPreview(p => !p)}\n          className={preview ? 'btn-primary' : 'btn-secondary'}>\n          <Eye size={15}/> {preview ? '\u1ea8n preview' : 'Xem preview'}\n        </button>\n      </div>\n\n      {error && <div className=\"alert-error mb-5\">{error}</div>}\n\n      <form onSubmit={handleSubmit}>\n        <div className={`grid gap-5 ${preview ? 'grid-cols-2' : 'grid-cols-1'}`}>\n          <div className=\"space-y-5\">\n            <div className=\"card\">\n              <div className=\"card-header\"><h2 className=\"text-sm font-semibold\">Ph\u00e2n lo\u1ea1i</h2></div>\n              <div className=\"card-body grid grid-cols-3 gap-4\">\n                <div>\n                  <label className=\"label\">Domain *</label>\n                  <select className=\"input\" value={form.domain} onChange={e => set('domain', e.target.value)}>\n                    {DOMAINS.map(d => <option key={d}>{d}</option>)}\n                  </select>\n                </div>\n                <div>\n                  <label className=\"label\">Skill *</label>\n                  <select className=\"input\" value={form.skill} onChange={e => set('skill', e.target.value)} required>\n                    <option value=\"\">Ch\u1ecdn skill</option>\n                    {skills.map(s => <option key={s} value={s}>{s}</option>)}\n                  </select>\n                </div>\n                <div>\n                  <label className=\"label\">\u0110\u1ed9 kh\u00f3 *</label>\n                  <select className=\"input\" value={form.difficulty} onChange={e => set('difficulty', e.target.value)}>\n                    {DIFFICULTIES.map(d => <option key={d}>{d}</option>)}\n                  </select>\n                </div>\n                <div className=\"col-span-3\">\n                  <label className=\"label\">Ngu\u1ed3n</label>\n                  <input className=\"input\" placeholder=\"VD: SAT Practice Test 1, Q5\"\n                    value={form.source} onChange={e => set('source', e.target.value)}/>\n                </div>\n              </div>\n            </div>\n\n            <div className=\"card\">\n              <div className=\"card-header\"><h2 className=\"text-sm font-semibold\">N\u1ed9i dung c\u00e2u h\u1ecfi</h2></div>\n              <div className=\"card-body\">\n                <textarea className=\"input font-mono text-sm\" rows={5}\n                  placeholder=\"Nh\u1eadp n\u1ed9i dung. D\u00f9ng $...$ cho inline math, $$...$$ cho display math.\"\n                  value={form.content} onChange={e => set('content', e.target.value)} required/>\n                <p className=\"text-xs text-gray-400 mt-1\">H\u1ed7 tr\u1ee3 LaTeX: $x^2$ ho\u1eb7c $$\\frac{'{a}'}{'{b}'}$$</p>\n              </div>\n            </div>\n\n            <div className=\"card\">\n              <div className=\"card-header\"><h2 className=\"text-sm font-semibold\">\u0110\u00e1p \u00e1n</h2></div>\n              <div className=\"card-body space-y-3\">\n                {ANSWERS.map(letter => (\n                  <div key={letter} className=\"flex items-center gap-3\">\n                    <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${\n                      form.correct_answer === letter ? 'bg-emerald-500 text-white' : 'bg-gray-100 text-gray-600'\n                    }`}>{letter}</div>\n                    <input className=\"input flex-1 text-sm\"\n                      placeholder={`\u0110\u00e1p \u00e1n ${letter}`}\n                      value={(form as any)[`option_${letter.toLowerCase()}`]}\n                      onChange={e => set(`option_${letter.toLowerCase()}`, e.target.value)} required/>\n                    <button type=\"button\" onClick={() => set('correct_answer', letter)}\n                      className={`text-xs px-2.5 py-1.5 rounded-lg font-medium transition-colors shrink-0 ${\n                        form.correct_answer === letter\n                          ? 'bg-emerald-100 text-emerald-700'\n                          : 'bg-gray-50 text-gray-400 hover:bg-emerald-50 hover:text-emerald-600'\n                      }`}>\n                      {form.correct_answer === letter ? '\u2713 \u0110\u00fang' : '\u0110\u00fang'}\n                    </button>\n                  </div>\n                ))}\n              </div>\n            </div>\n\n            <div className=\"card\">\n              <div className=\"card-header\"><h2 className=\"text-sm font-semibold\">Gi\u1ea3i th\u00edch (tu\u1ef3 ch\u1ecdn)</h2></div>\n              <div className=\"card-body\">\n                <textarea className=\"input font-mono text-sm\" rows={3}\n                  placeholder=\"Gi\u1ea3i th\u00edch \u0111\u00e1p \u00e1n \u0111\u00fang\u2026\"\n                  value={form.explanation} onChange={e => set('explanation', e.target.value)}/>\n              </div>\n            </div>\n\n            <div className=\"flex gap-3\">\n              <Link href=\"/admin/questions\" className=\"btn-secondary flex-1 justify-center\">Hu\u1ef7</Link>\n              <button type=\"submit\" disabled={isPending} className=\"btn-primary flex-1 justify-center\">\n                {isPending ? '\u0110ang l\u01b0u\u2026' : 'L\u01b0u c\u00e2u h\u1ecfi'}\n              </button>\n            </div>\n          </div>\n\n          {preview && (\n            <div className=\"space-y-4\">\n              <div className=\"card sticky top-4\">\n                <div className=\"card-header\"><h2 className=\"text-sm font-semibold text-blue-700\">Preview</h2></div>\n                <div className=\"card-body space-y-4\">\n                  <div>\n                    <p className=\"text-xs font-medium text-gray-500 mb-2\">\u0110\u1ec1 b\u00e0i</p>\n                    <div className=\"bg-gray-50 rounded-xl p-4 text-sm leading-relaxed\">\n                      <KaTeXPreview text={form.content || 'N\u1ed9i dung s\u1ebd hi\u1ec3n th\u1ecb \u1edf \u0111\u00e2y\u2026'}/>\n                    </div>\n                  </div>\n                  <div className=\"space-y-2\">\n                    <p className=\"text-xs font-medium text-gray-500\">\u0110\u00e1p \u00e1n</p>\n                    {ANSWERS.map(letter => (\n                      <div key={letter}\n                        className={`flex items-start gap-2.5 p-3 rounded-xl text-sm ${\n                          form.correct_answer === letter ? 'bg-emerald-50 border border-emerald-200' : 'bg-gray-50'\n                        }`}>\n                        <span className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${\n                          form.correct_answer === letter ? 'bg-emerald-500 text-white' : 'bg-gray-200 text-gray-600'\n                        }`}>{letter}</span>\n                        <KaTeXPreview text={(form as any)[`option_${letter.toLowerCase()}`] || '\u2014'}/>\n                      </div>\n                    ))}\n                  </div>\n                  {form.explanation && (\n                    <div className=\"bg-blue-50 rounded-xl p-4\">\n                      <p className=\"text-xs font-medium text-blue-700 mb-1\">Gi\u1ea3i th\u00edch</p>\n                      <div className=\"text-sm text-blue-800\"><KaTeXPreview text={form.explanation}/></div>\n                    </div>\n                  )}\n                </div>\n              </div>\n            </div>\n          )}\n        </div>\n      </form>\n    </div>\n  )\n}\n",
  "app/admin/questions/QuestionImportModal.tsx": "'use client'\n\nimport { useState, useTransition } from 'react'\nimport { importQuestionsFromCSV } from './actions'\nimport { X, Upload } from 'lucide-react'\nimport Papa from 'papaparse'\n\nexport default function QuestionImportModal({ onClose }: { onClose: () => void }) {\n  const [rows, setRows]     = useState<any[]>([])\n  const [error, setError]   = useState('')\n  const [result, setResult] = useState<any>(null)\n  const [isPending, start]  = useTransition()\n\n  function handleFile(e: React.ChangeEvent<HTMLInputElement>) {\n    const file = e.target.files?.[0]\n    if (!file) return\n    Papa.parse(file, {\n      header: true, skipEmptyLines: true,\n      complete: ({ data, errors }) => {\n        if (errors.length) { setError(errors[0].message); return }\n        setError('')\n        setRows(data as any[])\n      }\n    })\n  }\n\n  return (\n    <div className=\"modal-backdrop\">\n      <div className=\"modal w-full max-w-xl\">\n        <div className=\"flex items-center justify-between mb-5\">\n          <h2 className=\"text-base font-semibold text-gray-900\">Nh\u1eadp c\u00e2u h\u1ecfi t\u1eeb CSV</h2>\n          <button onClick={onClose} className=\"p-1 text-gray-400 hover:text-gray-600\"><X size={18}/></button>\n        </div>\n        {!result ? (\n          <>\n            <div className=\"bg-amber-50 border border-amber-200 rounded-xl p-4 mb-4 text-sm text-amber-800\">\n              <p className=\"font-medium mb-1\">C\u1ed9t b\u1eaft bu\u1ed9c:</p>\n              <code className=\"text-xs\">domain, skill, difficulty, content, option_a, option_b, option_c, option_d, correct_answer</code>\n            </div>\n            <div className=\"border-2 border-dashed border-gray-200 rounded-xl p-8 text-center mb-4\">\n              <Upload size={28} className=\"text-gray-300 mx-auto mb-3\"/>\n              <label className=\"btn-secondary cursor-pointer inline-flex\">\n                <input type=\"file\" accept=\".csv\" className=\"hidden\" onChange={handleFile}/>\n                Ch\u1ecdn file CSV\n              </label>\n            </div>\n            {error && <div className=\"alert-error mb-4\">{error}</div>}\n            {rows.length > 0 && (\n              <>\n                <p className=\"text-sm font-medium text-gray-600 mb-3\">{rows.length} c\u00e2u h\u1ecfi s\u1ebd \u0111\u01b0\u1ee3c nh\u1eadp</p>\n                <div className=\"flex gap-3\">\n                  <button onClick={onClose} className=\"btn-secondary flex-1\">Hu\u1ef7</button>\n                  <button onClick={() => start(async () => setResult(await importQuestionsFromCSV(rows)))}\n                    disabled={isPending} className=\"btn-primary flex-1 justify-center\">\n                    {isPending ? '\u0110ang nh\u1eadp\u2026' : `Nh\u1eadp ${rows.length} c\u00e2u h\u1ecfi`}\n                  </button>\n                </div>\n              </>\n            )}\n          </>\n        ) : (\n          <div className=\"text-center py-6\">\n            {result.success\n              ? <><div className=\"text-4xl mb-3\">\u2705</div><p className=\"font-semibold text-gray-900\">Nh\u1eadp th\u00e0nh c\u00f4ng {result.count} c\u00e2u h\u1ecfi!</p></>\n              : <><div className=\"text-4xl mb-3\">\u274c</div><p className=\"text-red-600\">{result.error}</p></>}\n            <button onClick={onClose} className=\"btn-primary mt-5\">\u0110\u00f3ng</button>\n          </div>\n        )}\n      </div>\n    </div>\n  )\n}\n",
  "app/admin/questions/QuestionDeleteBtn.tsx": "'use client'\n\nimport { useTransition } from 'react'\nimport { deleteQuestion } from './actions'\nimport { Trash2 } from 'lucide-react'\n\ninterface Props { id: string; onDone: () => void }\n\nexport default function QuestionDeleteBtn({ id, onDone }: Props) {\n  const [isPending, start] = useTransition()\n\n  function handleDelete() {\n    if (!confirm('Xo\u00e1 c\u00e2u h\u1ecfi n\u00e0y? H\u00e0nh \u0111\u1ed9ng kh\u00f4ng th\u1ec3 ho\u00e0n t\u00e1c.')) return\n    start(async () => { await deleteQuestion(id); onDone() })\n  }\n\n  return (\n    <button onClick={handleDelete} disabled={isPending} title=\"Xo\u00e1 c\u00e2u h\u1ecfi\"\n      className=\"p-1.5 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors\">\n      <Trash2 size={15}/>\n    </button>\n  )\n}\n",
  "app/student/dashboard/page.tsx": "import { redirect } from 'next/navigation'\nimport { createClient } from '@/lib/supabase/server'\nimport { formatDate } from '@/lib/utils'\nimport { TIER_LABELS } from '@/types'\nimport { ClipboardList, TrendingUp, Target, BookOpen } from 'lucide-react'\nimport Link from 'next/link'\n\nexport default async function StudentDashboardPage() {\n  const supabase = await createClient()\n  const { data: { user } } = await supabase.auth.getUser()\n  if (!user) redirect('/login')\n\n  const { data: profile } = await supabase\n    .from('users').select('full_name, email, tier').eq('auth_id', user.id).single()\n  if (!profile) redirect('/login')\n\n  const { data: assignments } = await supabase\n    .from('assignments').select('id, title, due_date, created_at')\n    .order('created_at', { ascending: false }).limit(5)\n\n  const { data: sessions } = await supabase\n    .from('sessions')\n    .select('id, score, total_questions, correct_count, finished_at, assignments(title)')\n    .eq('user_id', user.id).not('finished_at', 'is', null)\n    .order('finished_at', { ascending: false }).limit(5)\n\n  const hour = new Date().getHours()\n  const greet = hour < 12 ? 'Ch\u00e0o bu\u1ed5i s\u00e1ng' : hour < 18 ? 'Ch\u00e0o bu\u1ed5i chi\u1ec1u' : 'Ch\u00e0o bu\u1ed5i t\u1ed1i'\n\n  return (\n    <div className=\"p-6 max-w-5xl mx-auto\">\n      <div className=\"bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl p-6 mb-6 text-white\">\n        <p className=\"text-blue-200 text-sm mb-1\">{greet},</p>\n        <h1 className=\"text-2xl font-bold mb-1\">{profile.full_name} \ud83d\udc4b</h1>\n        <p className=\"text-blue-100 text-sm\">{profile.email}</p>\n        {profile.tier && (\n          <div className=\"mt-3 inline-flex items-center gap-1.5 bg-white/20 px-3 py-1.5 rounded-full\">\n            <Target size={14}/>\n            <span className=\"text-sm font-medium\">{TIER_LABELS[profile.tier as keyof typeof TIER_LABELS]}</span>\n          </div>\n        )}\n      </div>\n\n      {!profile.tier && (\n        <div className=\"card mb-6 border-amber-200 bg-amber-50\">\n          <div className=\"card-body flex items-center gap-4\">\n            <div className=\"w-10 h-10 bg-amber-100 rounded-xl flex items-center justify-center shrink-0\">\n              <Target size={20} className=\"text-amber-600\"/>\n            </div>\n            <div>\n              <p className=\"font-semibold text-amber-900\">B\u1ea1n ch\u01b0a c\u00f3 Tier h\u1ecdc t\u1eadp</p>\n              <p className=\"text-sm text-amber-700 mt-0.5\">Li\u00ean h\u1ec7 gi\u00e1o vi\u00ean \u0111\u1ec3 \u0111\u01b0\u1ee3c ph\u00e2n lo\u1ea1i v\u00e0 nh\u1eadn b\u00e0i t\u1eadp ph\u00f9 h\u1ee3p.</p>\n            </div>\n          </div>\n        </div>\n      )}\n\n      <div className=\"grid grid-cols-2 gap-5\">\n        <div className=\"card\">\n          <div className=\"card-header\">\n            <div className=\"flex items-center gap-2\">\n              <ClipboardList size={16} className=\"text-blue-600\"/>\n              <h2 className=\"text-sm font-semibold text-gray-900\">B\u00e0i t\u1eadp</h2>\n            </div>\n            <Link href=\"/student/assignments\" className=\"text-xs text-blue-600 hover:underline\">Xem t\u1ea5t c\u1ea3</Link>\n          </div>\n          <div className=\"divide-y divide-gray-100\">\n            {assignments?.length ? assignments.map(a => (\n              <div key={a.id} className=\"px-5 py-3.5 flex items-center justify-between hover:bg-gray-50 transition-colors\">\n                <div>\n                  <p className=\"text-sm font-medium text-gray-900\">{a.title}</p>\n                  {a.due_date && <p className=\"text-xs text-gray-400 mt-0.5\">H\u1ea1n: {formatDate(a.due_date)}</p>}\n                </div>\n                <Link href={`/student/assignments/${a.id}`} className=\"btn-primary text-xs px-3 py-1.5\">L\u00e0m b\u00e0i</Link>\n              </div>\n            )) : (\n              <div className=\"empty-state py-10\">\n                <BookOpen size={28} className=\"text-gray-200 mb-2\"/>\n                <p className=\"text-sm text-gray-400\">Ch\u01b0a c\u00f3 b\u00e0i t\u1eadp n\u00e0o</p>\n              </div>\n            )}\n          </div>\n        </div>\n\n        <div className=\"card\">\n          <div className=\"card-header\">\n            <div className=\"flex items-center gap-2\">\n              <TrendingUp size={16} className=\"text-emerald-600\"/>\n              <h2 className=\"text-sm font-semibold text-gray-900\">K\u1ebft qu\u1ea3 g\u1ea7n \u0111\u00e2y</h2>\n            </div>\n            <Link href=\"/student/results\" className=\"text-xs text-blue-600 hover:underline\">Xem t\u1ea5t c\u1ea3</Link>\n          </div>\n          <div className=\"divide-y divide-gray-100\">\n            {sessions?.length ? sessions.map(s => {\n              const pct = s.total_questions > 0 ? Math.round((s.correct_count / s.total_questions) * 100) : 0\n              return (\n                <div key={s.id} className=\"px-5 py-3.5\">\n                  <div className=\"flex items-center justify-between mb-1.5\">\n                    <p className=\"text-sm font-medium text-gray-800 truncate max-w-[60%]\">\n                      {(s.assignments as any)?.title ?? 'B\u00e0i luy\u1ec7n t\u1eadp'}\n                    </p>\n                    <span className={`text-sm font-bold ${pct >= 70 ? 'text-emerald-600' : pct >= 50 ? 'text-amber-500' : 'text-red-500'}`}>\n                      {pct}%\n                    </span>\n                  </div>\n                  <div className=\"progress-track mb-1\">\n                    <div className={`progress-fill ${pct >= 70 ? 'bg-emerald-400' : pct >= 50 ? 'bg-amber-400' : 'bg-red-400'}`}\n                      style={{ width: `${pct}%` }}/>\n                  </div>\n                  <p className=\"text-xs text-gray-400\">{s.correct_count}/{s.total_questions} c\u00e2u \u0111\u00fang</p>\n                </div>\n              )\n            }) : (\n              <div className=\"empty-state py-10\">\n                <TrendingUp size={28} className=\"text-gray-200 mb-2\"/>\n                <p className=\"text-sm text-gray-400\">Ch\u01b0a c\u00f3 k\u1ebft qu\u1ea3 n\u00e0o</p>\n              </div>\n            )}\n          </div>\n        </div>\n      </div>\n    </div>\n  )\n}\n"
};

let ok = 0, fail = 0;
for (const [relPath, content] of Object.entries(files)) {
  const fullPath = path.join(__dirname, relPath);
  try {
    fs.mkdirSync(path.dirname(fullPath), { recursive: true });
    fs.writeFileSync(fullPath, content, 'utf8');
    console.log('\x1b[32m  OK\x1b[0m', relPath);
    ok++;
  } catch(e) {
    console.log('\x1b[31m FAIL\x1b[0m', relPath, '-', e.message);
    fail++;
  }
}
console.log(`\n${ok} files created${fail ? ', ' + fail + ' FAILED' : '. All done!'}`);
if (fail > 0) {
  console.log('\n\x1b[33mTo fix failed files:\x1b[0m');
  console.log('  1. In Windows Explorer, delete these folders:');
  console.log('       app\\admin\\dashboard');
  console.log('       app\\admin\\users');
  console.log('       app\\admin\\questions');
  console.log('       app\\student\\dashboard');
  console.log('  2. Run again: node create_pages.js');
}
